187→    async loadTasks() {
188→        this.taskList = await dailyReportAiApis.getEmailTaskList()
189→        if (this.selectedTask) {
190→            // 如果当前选中的任务还在列表中，刷新它
191→            const found = this.taskList.find(t => t.id === this.selectedTask!.id)
192→            if (found) {
193→                this.selectTask(found)
