205→        this.form = {
206→            name: task.name,
207→            dimension: task.dimension,
208→            report_range: task.report_range,
209→            send_cycle: task.send_cycle,
210→            send_day: task.send_day ?? 1,
211→            send_time: task.send_time,
212→            system_prompt: task.system_prompt,
213→        }
214→    }
