290→            this.saving = false
291→        }
292→    }
293→
294→    async handleDelete() {
295→        if (!this.selectedTask) return
296→        try {
297→            await MessageBox.confirm('确定删除该任务？', '提示', { type: 'warning' })
298→        } catch {
299→            return
300→        }
301→        await dailyReportAiApis.deleteEmailTask(this.selectedTask.id)
302→        this.selectedTask = null
303→        Message.success('已删除')
304→        await this.loadTasks()
305→    }
306→
307→    async handleTrigger() {
308→        if (!this.selectedTask) return
309→        try {
310→            await MessageBox.confirm(
311→                '将立即为该任务的所有分组生成 AI 分析并发送邮件，确认执行？',
312→                '立即发送',
313→                { type: 'warning', confirmButtonText: '确认发送', cancelButtonText: '取消' }
314→            )
315→        } catch {
316→            return
317→        }
318→        this.triggering = true
319→        try {
320→            const ok = await dailyReportAiApis.triggerEmailTask(this.selectedTask.id)
321→            if (ok) {
