323→            }
324→        } finally {
325→            this.triggering = false
326→        }
327→    }
328→
329→    handleTest() {
330→        if (!this.form.system_prompt.trim()) {
331→            Message.warning('请先输入 AI 分析 Prompt')
332→            return
333→        }
334→        this.showTestDialog = true
335→    }
336→
337→    async handleToggle(task: AiEmailTask, val: boolean) {
338→        await dailyReportAiApis.toggleEmailTask(task.id, val ? 1 : 0)
339→        await this.loadTasks()
340→    }
