320→
321→        // 校验会话归属
322→        $session = DB::table('daily_report_ai_sessions')
323→            ->where('id', $sessionId)
324→            ->where('sfuser_id', $sfuserId)
325→            ->whereNull('deleted_at')
326→            ->first();
327→
328→        if (!$session) {
329→            return $this->responseJsonSuccess(['list' => []]);
