458→    public function extractSlots(Request $request): JsonResponse
459→    {
460→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
461→        if (!$this->inWhitelist($sfuserId)) {
462→            return $this->responseJsonFail('无权限');
463→        }
464→
465→        $message = $request->input('message');
466→        $conversationId = $request->input('conversation_id', '');
467→        $availableGroups = $request->input('available_groups', []);
468→        $availableMembers = $request->input('available_members', []);
469→        $previousContext = $request->input('previous_context');
470→        $hasExistingContext = $request->boolean('has_existing_context', false);
471→
472→        // 将可用分组和成员列表格式化为 prompt 中的列表
473→        $groupList = !empty($availableGroups)
474→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
475→            : '   - （无可用分组）';
476→        $memberList = !empty($availableMembers)
477→            ? implode('、', $availableMembers)
478→            : '（无可用成员列表）';
479→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
480→        $prevCtx = '无（首次查询）';
481→        if (!empty($previousContext)) {
482→            $prevMembers = implode('、', $previousContext['members'] ?? []);
483→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
484→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
485→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
486→        }
487→        $hasContextLabel = $hasExistingContext ? '是' : '否';
488→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
489→
490→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
491→            'sfuser_id' => $sfuserId,
492→            'message' => $message,
493→            'previous_context' => $previousContext,
494→            'available_groups' => $availableGroups,
495→            'member_count' => count($availableMembers),
496→        ]);
497→
498→        // 返回 message + ai_analysis_config，由 oa-core TransferRequestService 做 blocking AI 调用
499→        return $this->responseJsonSuccess([
500→            'message' => $message,
501→            'ai_analysis_config' => [
502→                'system_prompt' => $systemPrompt,
503→                'target_field' => 'message',
504→                'output_field' => 'ai_result',
505→            ],
506→        ]);
507→    }
