509→    // ----------------------------------------------------------------
510→    // 发送消息（SSE 流式）
511→    // ----------------------------------------------------------------
512→
513→    public function ask(Request $request): JsonResponse
514→    {
515→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
516→        if (!$this->inWhitelist($sfuserId)) {
517→            return $this->responseJsonFail('无权限');
518→        }
519→        $roleId = $request->input('role_id');
520→        $sessionId = $request->input('session_id');
521→        $message = $request->input('message');
522→        $reportContext = $request->input('report_context', '');
523→        $reportContextRaw = $request->input('report_context_raw', '');
524→
525→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
526→        if (str_starts_with($reportContext, 'gz:')) {
527→            $decoded = base64_decode(substr($reportContext, 3), true);
528→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
529→        }
530→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
531→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
532→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
533→            'bytes' => strlen($reportContext),
534→            'chars' => mb_strlen($reportContext),
535→        ]);
536→
537→        // 校验角色归属
538→        $role = DB::table('daily_report_ai_roles')
539→            ->where('id', $roleId)
540→            ->where('sfuser_id', $sfuserId)
541→            ->whereNull('deleted_at')
542→            ->first();
543→
544→        if (!$role) {
545→            return $this->responseJsonFail('角色不存在');
546→        }
547→
548→        // 创建或复用会话
549→        if (!$sessionId) {
550→            $title = mb_substr($message, 0, 20);
551→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
552→                'sfuser_id' => $sfuserId,
553→                'role_id' => $roleId,
554→                'title' => $title,
555→                'created_at' => now(),
556→                'updated_at' => now(),
557→            ]);
558→        } else {
559→            $sessionRow = DB::table('daily_report_ai_sessions')
560→                ->where('id', $sessionId)
561→                ->where('sfuser_id', $sfuserId)
562→                ->whereNull('deleted_at')
563→                ->first();
564→            if (!$sessionRow) {
565→                return $this->responseJsonFail('会话不存在');
566→            }
567→        }
568→
569→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
570→        if (str_starts_with($reportContextRaw, 'gz:')) {
571→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
572→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
573→        }
574→
575→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
576→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
577→        if (!empty($contextToStore)) {
578→            DB::table('daily_report_ai_messages')->insert([
579→                'session_id' => $sessionId,
580→                'role' => 'context',
581→                'content' => $contextToStore,
582→                'created_at' => now(),
583→            ]);
584→        }
585→
586→        // 保存用户消息
587→        DB::table('daily_report_ai_messages')->insert([
588→            'session_id' => $sessionId,
589→            'role' => 'user',
590→            'content' => $message,
591→            'created_at' => now(),
592→        ]);
593→
594→        // 更新会话时间
595→        DB::table('daily_report_ai_sessions')
596→            ->where('id', $sessionId)
597→            ->update(['updated_at' => now()]);
598→
599→        // 构建发送给 AI 的内容
600→        $queryParts = [];
601→        if (!empty($reportContext)) {
602→            $queryParts[] = "[日报数据]\n{$reportContext}";
603→        }
604→        $queryParts[] = $message;
605→        $query = implode("\n\n---\n\n", $queryParts);
606→
607→        \Log::info('[lbl][0416-AI日报][AiAsk] request', [
608→            'session' => $sessionId,
609→            'query_len' => mb_strlen($query),
610→        ]);
611→
612→        // 返回 query + session_id，AI streaming 由 oa-core TransferRequestService 完成
613→        return $this->responseJsonSuccess([
614→            'query' => $query,
615→            'session_id' => $sessionId,
616→        ]);
617→    }
618→
619→    private function inWhitelist(int $sfuserId): bool
620→    {
621→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
622→        if (!$setting || !$setting->is_on) {
623→            return false;
624→        }
625→        return in_array($sfuserId, $setting->ids ?? []);
626→    }
627→}
