155→    /**
156→     * 测试 Prompt 效果：后端查询加密日报数据，返回 JSON，AI 分析由 oa-core TransferRequestService 完成。
157→     */
158→    public function taskTest(Request $request): JsonResponse
159→    {
160→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
161→        if (!$this->inWhitelist($sfuserId)) {
162→            return $this->responseJsonFail('无权限');
163→        }
164→
165→        $systemPrompt = $request->input('system_prompt', '');
166→        $dimension = $request->input('dimension', 'department');
167→        $reportRange = $request->input('report_range', 'today');
168→        $groupKey = $request->input('group_key', '');
169→
170→        // 计算日期范围
171→        $today = now()->toDateString();
172→        [$startDate, $endDate] = match ($reportRange) {
173→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
174→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
175→            default => [$today, $today],
176→        };
177→
178→        // 拉取该用户能看到日报的全部员工
179→        $dailyService = app(DailyReportService::class);
180→        $subordinates = $dailyService->getSubordinates($sfuserId);
181→        $groupUserIds = [];
182→        foreach ($subordinates['group_users'] as $userIds) {
183→            $groupUserIds = array_merge($groupUserIds, $userIds);
184→        }
185→        $targetUserIds = array_unique(array_merge(
186→            $subordinates['direct_subordinates'],
187→            $subordinates['depart_subordinates'],
188→            $subordinates['other_subordinates'],
189→            $subordinates['focus_users'],
190→            $groupUserIds
191→        ));
192→
193→        if (empty($targetUserIds)) {
194→            return $this->responseJsonFail('没有可查看的员工');
195→        }
196→
197→        // 拉取日报数据
198→        $data = $dailyService->getOthersDailyReportListEnable($startDate, $endDate, $sfuserId, $targetUserIds, 10000);
199→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
200→            return $this->responseJsonFail('所选日期范围内没有日报数据');
201→        }
202→
203→        $reportList = $data['reports']['report_list'];
204→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
205→
206→        // 构建分组映射
207→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $dimension);
208→
209→        // 按维度分组日报
210→        $grouped = [];
211→        foreach ($reportList as $report) {
212→            $uid = $report['sfuser_id'];
213→            $key = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
214→            $grouped[$key]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
215→            $grouped[$key]['reports'][] = $report;
216→        }
217→
218→        // 找到用户选中的分组，找不到则取第一个
219→        $targetGroup = $grouped[$groupKey] ?? reset($grouped);
220→        if (empty($targetGroup) || empty($targetGroup['reports'])) {
221→            return $this->responseJsonFail('所选分组没有日报数据');
222→        }
223→
224→        // 构建带加密标记的内容（oa-core 负责解密）
225→        $groupNameMarked = EncryptService::app()->markEncrString($targetGroup['name']);
226→        $content = "【分组：{$groupNameMarked}】\n\n";
227→        $no = 0;
228→        foreach ($targetGroup['reports'] as $report) {
229→            $nickname = $report['data']['nickname'] ?? '';
230→            if (empty($nickname)) {
231→                continue;
232→            }
233→            $nickname = EncryptService::app()->markEncrString(e($nickname));
234→            $reportContent = EncryptService::app()->markEncrString($report['content']);
235→            ++$no;
236→            $content .= $no.'、 '.$nickname."\n".$reportContent."\n\n";
237→        }
238→
239→        if ($no === 0) {
240→            return $this->responseJsonFail('该分组没有有效的日报内容');
241→        }
242→
243→        \Log::info('[lbl][0416-AI日报][AiEmail][TEST] 开始测试 Prompt', [
244→            'sfuser_id' => $sfuserId,
245→            'dimension' => $dimension,
246→            'group_key' => $groupKey,
247→            'group_name' => $targetGroup['name'],
248→            'report_count' => $no,
249→            'content_len' => mb_strlen($content),
250→        ]);
251→
252→        // 从 MailConfig 读取 sfuser_authorized_token
253→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
254→        $sfuserToken = $mc ? Arr::get($mc->config, 'sfuser_authorized_token', '') : '';
255→        if (empty($sfuserToken)) {
256→            return $this->responseJsonFail('未配置邮件授权 Token，请先在管理后台配置邮件');
257→        }
258→
259→        // 构建摘要
260→        $dimensionLabel = $dimension === 'direct_manager' ? '按直接主管' : '按部门';
261→        $rangeLabel = match ($reportRange) {
262→            'last_3_days' => '近3天',
263→            'last_7_days' => '近7天',
264→            default => '今日',
265→        };
266→        $dateRange = $startDate === $endDate ? $startDate : "{$startDate} ~ {$endDate}";
267→
268→        // 返回数据 + decrypt_config + ai_analysis_config，由 oa-core TransferRequestService 做解密+AI streaming
269→        return $this->responseJsonSuccess([
270→            'content' => $content,
271→            'summary' => "{$dimensionLabel} · {$rangeLabel}（{$dateRange}）· {$no}份日报",
272→            'decrypt_config' => [
273→                'obj' => '$this',
274→                'decrypt_columns' => [],
275→                'partly_decrypt_columns' => ['content'],
276→                'tokens' => [$sfuserToken],
277→                'operation' => 'send_email',
278→            ],
279→            'ai_analysis_config' => [
280→                'system_prompt' => $systemPrompt,
281→                'target_field' => 'content',
282→                'compress' => true,
283→            ],
284→        ]);
285→    }
