287→    /**
288→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
289→     * 复用 DailyReportAiEmailJob 中的分组逻辑.
290→     */
291→    private function buildGroupMap(array $sfuserIds, string $dimension): array
292→    {
293→        if (empty($sfuserIds)) {
294→            return [];
295→        }
296→
297→        $map = [];
298→
299→        if ($dimension === 'direct_manager') {
300→            $users = Sfuser::whereIn('id', $sfuserIds)
301→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
302→                ->get();
303→            foreach ($users as $user) {
304→                $managerId = $user->direct_supervisor_id ?: 0;
305→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
306→                $map[$user->id] = [
307→                    'key' => "mgr_{$managerId}",
308→                    'name' => $managerName,
309→                ];
310→            }
311→        } else {
312→            $users = Sfuser::whereIn('id', $sfuserIds)
313→                ->select('id', 'department_id')
314→                ->get();
315→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
316→            $deptNames = [];
317→            if (!empty($deptIds)) {
318→                $deptNames = DB::table('job_departments')
319→                    ->whereIn('department_id', $deptIds)
320→                    ->pluck('department_name', 'department_id')
321→                    ->toArray();
322→            }
323→            foreach ($users as $user) {
324→                $deptId = $user->department_id ?: 0;
325→                $deptName = $deptNames[$deptId] ?? '未分配部门';
326→                $map[$user->id] = [
327→                    'key' => "dept_{$deptId}",
328→                    'name' => $deptName,
329→                ];
330→            }
331→        }
332→
333→        return $map;
334→    }
335→
336→    private function inWhitelist(int $sfuserId): bool
337→    {
338→        // 复用 DailyReportAiController 相同的白名单逻辑，从 oa_settings 表动态读取
339→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
340→        if (!$setting || !$setting->is_on) {
341→            return false;
342→        }
343→        return in_array($sfuserId, $setting->ids ?? []);
344→    }
345→}
