236→    /**
237→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
238→     */
239→    private function buildGroupMap(array $sfuserIds, string $dimension): array
240→    {
241→        if (empty($sfuserIds)) {
242→            return [];
243→        }
244→
245→        $map = [];
246→
247→        if ($dimension === 'direct_manager') {
248→            // 按直接主管分组
249→            $users = Sfuser::whereIn('id', $sfuserIds)
250→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
251→                ->get();
252→
253→            foreach ($users as $user) {
254→                $managerId = $user->direct_supervisor_id ?: 0;
255→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
256→                $map[$user->id] = [
257→                    'key' => "mgr_{$managerId}",
258→                    'name' => $managerName,
259→                ];
260→            }
261→        } else {
262→            // 按部门分组
263→            $users = Sfuser::whereIn('id', $sfuserIds)
264→                ->select('id', 'department_id')
265→                ->get();
266→
267→            // 批量查部门名称
268→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
269→            $deptNames = [];
270→            if (!empty($deptIds)) {
271→                $deptNames = DB::table('job_departments')
272→                    ->whereIn('department_id', $deptIds)
273→                    ->pluck('department_name', 'department_id')
274→                    ->toArray();
275→            }
276→
277→            foreach ($users as $user) {
278→                $deptId = $user->department_id ?: 0;
279→                $deptName = $deptNames[$deptId] ?? '未分配部门';
280→                $map[$user->id] = [
281→                    'key' => "dept_{$deptId}",
282→                    'name' => $deptName,
283→                ];
284→            }
285→        }
286→
287→        return $map;
288→    }
